module SRAM_Cell(  
    input [7:0] data_in,  
    input we,  
    output reg [7:0] data_out  
);  
    reg [7:0] memory;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge we or posedge dbg_halt) begin  
        memory <= data_in;  
    end  

    always @(*) begin  
        data_out = memory;  
    end  
endmodule
